class Solution:
    def longestCycle(self, edges):
        n = len(edges)
        visited = [False] * n
        ans = -1
        for i in range(n):
            if visited[i]:
                continue
            stamp = {}
            cur = i
            step = 0
            while cur != -1 and not visited[cur]:
                if cur in stamp:
                    ans = max(ans, step - stamp[cur])
                    break
                stamp[cur] = step
                step += 1
                cur = edges[cur]
            for node in stamp:
                visited[node] = True
        return ans

