var longestCycle = function(edges) {
    const n = edges.length;
    const visited = new Array(n).fill(false);
    let ans = -1;
    for (let i = 0; i < n; i++) {
        if (visited[i]) continue;
        const stamp = new Map();
        let cur = i, step = 0;
        while (cur !== -1 && !visited[cur]) {
            if (stamp.has(cur)) {
                ans = Math.max(ans, step - stamp.get(cur));
                break;
            }
            stamp.set(cur, step);
            step += 1;
            cur = edges[cur];
        }
        for (const node of stamp.keys()) visited[node] = true;
    }
    return ans;
};
